SELECT /*+ USE_INDEX(t_erp_fin_invoice idx_status, idx_factory_id) */  FROM t_erp_fin_invoice

    AND invoice_no = #{invoiceNo}
    AND customer_name LIKE CONCAT('%',#{customerName},'%')
    AND status = #{status}
    AND factory_id = #{factoryId}

${params.factoryDataScope}
ORDER BY create_time DESC
